+#   rays: int [N, 3], id, offset, num_steps
+class _generate_points(Function):
+    @staticmethod
+    def forward(ctx, rays_o, rays_d, bound, density_grid, mean_density, iter_density):
+        
+        rays_o = rays_o.reshape(-1, 3).contiguous()
